**Masalah:** Di `stats/route.ts`, tiap kelas menjalankan query siswa ID terpisah padahal `monthlyKehadiran` sudah di-load:

```ts
const perKelas = await Promise.all(
  kelasList.map(async (k) => {
    const ids = (await prisma.siswa.findMany({     // ← N query
      where: { kelasId: k.id }, select: { id: true }
    })).map(s => s.id);
    ...
  })
);
```

**Fix:** Pre-load semua siswa per kelas dalam 1 query, lalu filter in-memory:

```ts
// Pre-load once
const allSiswa = await prisma.siswa.findMany({
  select: { id: true, kelasId: true },
});
const siswaByKelas = new Map<string, string[]>();
for (const s of allSiswa) {
  if (!siswaByKelas.has(s.kelasId)) siswaByKelas.set(s.kelasId, []);
  siswaByKelas.get(s.kelasId)!.push(s.id);
}

const perKelas = kelasList.map((k) => {
  const ids = siswaByKelas.get(k.id) || [];
  const khd = monthlyKehadiran.filter(h => ids.includes(h.siswaId));
  // ...
});
```

