**Masalah:** `/api/admin/stats` di-query tiap kali admin buka dashboard. Monthly attendance di-rekalkulasi dari DB setiap request. Bisa pakai `stale-while-revalidate`.

**Fix — simple in-memory cache (no extra deps):**

```ts
// src/app/api/admin/stats/route.ts — tambah di luar handler
const cache = new Map<string, { data: any; expiry: number }>();
const CACHE_TTL = 60_000; // 1 menit

export async function GET(request: NextRequest) {
  const cacheKey = 'admin-stats';
  const cached = cache.get(cacheKey);
  if (cached && cached.expiry > Date.now()) {
    return NextResponse.json(cached.data);
  }
  // ... existing logic ...
  cache.set(cacheKey, { data: result, expiry: Date.now() + CACHE_TTL });
  return NextResponse.json(result);
}
```

